function changeLang(t){fetch(`/translations/${t}.json`).then(t=>t.json()).then(e=>{document.querySelectorAll("[data-i18n]").forEach(t=>{const a=t.getAttribute("data-i18n");e[a]&&(t.textContent=e[a])}),document.querySelectorAll("[data-i18n-placeholder]").forEach(t=>{const a=t.getAttribute("data-i18n-placeholder");e[a]&&(t.placeholder=e[a])}),document.querySelectorAll("[data-i18n-title]").forEach(t=>{const a=t.getAttribute("data-i18n-title");e[a]&&(t.title=e[a])}),applyCategoryNames(t),localStorage.setItem("lang",t),document.documentElement.lang=t,document.documentElement.dir="ar"===t?"rtl":"ltr"})}function applyCategoryNames(t){document.querySelectorAll("[data-i18n-ar], [data-i18n-en]").forEach(e=>{const a=e.getAttribute("data-i18n-ar"),n=e.getAttribute("data-i18n-en"),o="en"===t?n||a:a||n;o&&(e.textContent=o)})}window.applyCategoryNames=applyCategoryNames,window.addEventListener("DOMContentLoaded",()=>{const t=new URLSearchParams(location.search).get("lang"),e="en"===t||"ar"===t?t:localStorage.getItem("lang")||"ar";localStorage.setItem("lang",e),changeLang(e);const a=document.querySelector("select");a&&(a.value=e)});